3	export type Customer = {
4	  yearsWithMHPCO: number;
5	  previousContracts?: number;
6	};
7	
8	export type Item = {
9	  type: string;
10	  material?: string;
11	  enchantment?: number;
12	  cursed?: boolean;
13	};
14	
15	export type QuoteInput = {
16	  customer: Customer;
17	  items: Item[];
18	};
19	
20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_RATE = 0.1;
22	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
23	const LOYALTY_DISCOUNT_RATE = 0.2;
24	const LOYALTY_YEARS_THRESHOLD = 2;
25	const CURSED_SURCHARGE_RATE = 0.5;
26	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	const COMPONENT_BASE = 25;
29	const COMPONENT_BLOCK_PREMIUM = 60;
30	const CLAIM_DEDUCTIBLE = 100;
31	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
32	const CLAIM_HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
33	
34	const ITEM_BASE_PREMIUMS: Record<string, number> = {
35	  sword: 100,
36	  amulet: 60,
37	  staff: 80,
38	  potion: 40,
39	  rune: 25,
40	  moonstone: 25,
41	};
42	
43	function isComponentType(type: string): boolean {
44	  return ITEM_BASE_PREMIUMS[type] === COMPONENT_BASE;
45	}
46	
47	function groupItemsByType(items: Item[]): Map<string, Item[]> {
48	  const groups = new Map<string, Item[]>();
49	  for (const item of items) {
50	    const group = groups.get(item.type) ?? [];
51	    group.push(item);
52	    groups.set(item.type, group);
53	  }
54	  return groups;
55	}
56	
57	function totalSurchargeRate(item: Item): number {
58	  const cursedRate = item.cursed ? CURSED_SURCHARGE_RATE : 0;
59	  const highEnchantmentRate =
60	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
61	      ? HIGH_ENCHANTMENT_SURCHARGE_RATE
62	      : 0;
63	  return cursedRate + highEnchantmentRate;
64	}
65	
66	function calculateItemSurcharge(type: string, item: Item): number {
67	  const base = ITEM_BASE_PREMIUMS[type];
68	  return base * totalSurchargeRate(item);
69	}
70	
71	function calculateGroupBase(type: string, group: Item[]): number {
72	  if (isComponentType(type) && group.length === 3) {
73	    return COMPONENT_BLOCK_PREMIUM;
74	  }
75	  return group.length * ITEM_BASE_PREMIUMS[type];
76	}
77	
78	function calculatePolicyBase(items: Item[]): number {
79	  const groups = groupItemsByType(items);
80	  return Array.from(groups).reduce(
81	    (total, [type, group]) => total + calculateGroupBase(type, group),
82	    0
83	  );
84	}
85	
86	function calculateItemSurcharges(items: Item[]): number {
87	  return items.reduce(
88	    (total, item) => total + calculateItemSurcharge(item.type, item),
89	    0
90	  );
91	}
92	
93	function calculateLoyaltyDiscount(customer: Customer, policyBase: number): number {
94	  if (customer.yearsWithMHPCO < LOYALTY_YEARS_THRESHOLD) {
95	    return 0;
96	  }
97	  return policyBase * LOYALTY_DISCOUNT_RATE;
98	}
99	
100	function calculateFollowUpDiscount(customer: Customer, policyBase: number): number {
101	  const hasPreviousContracts = (customer.previousContracts ?? 0) >= 1;
102	  if (!hasPreviousContracts) {
103	    return 0;
104	  }
105	  return policyBase * FOLLOW_UP_DISCOUNT_RATE;
106	}
107	
108	function calculateFirstInsuranceSurcharge(policyBase: number): number {
109	  return policyBase * FIRST_INSURANCE_RATE;
110	}
111	
112	export type Damage = {
113	  itemType: string;
114	  amount: number;
115	};
116	
117	export type Incident = {
118	  cause: string;
119	  damages: Damage[];
120	};
121	
122	export type PolicyState = {
123	  items: Item[];
124	  remainingCap: number;
125	};
126	
127	export type ClaimInput = {
128	  policy: PolicyState;
129	  incident: Incident;
130	};
131	
132	export type ClaimResult = {
133	  payout: number;
134	  remainingCap: number;
135	};
136	
137	function isHighEnchantmentForClaim(item: Item | undefined): boolean {
138	  return (item?.enchantment ?? 0) >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD;
139	}
140	
141	function calculateDamagePayout(damage: Damage, items: Item[]): number {
142	  const item = items.find((i) => i.type === damage.itemType);
143	  const adjustedDamage = isHighEnchantmentForClaim(item)
144	    ? damage.amount * CLAIM_HIGH_ENCHANTMENT_PAYOUT_RATE
145	    : damage.amount;
146	  return Math.max(adjustedDamage - CLAIM_DEDUCTIBLE, 0);
147	}
148	
149	function sumDamagePayouts(damages: Damage[], items: Item[]): number {
150	  return damages.reduce(
151	    (total, damage) => total + calculateDamagePayout(damage, items),
152	    0
153	  );
154	}
155	
156	function capPayout(payout: number, remainingCap: number): number {
157	  return Math.min(payout, remainingCap);
158	}
159	
160	export function claim(input: ClaimInput): ClaimResult {
161	  const rawPayout = Math.floor(sumDamagePayouts(input.incident.damages, input.policy.items));
162	  const payout = capPayout(rawPayout, input.policy.remainingCap);
163	  return { payout, remainingCap: input.policy.remainingCap - payout };
164	}
165	
166	const ITEM_INSURANCE_VALUES: Record<string, number> = {
167	  sword: 1000,
168	  amulet: 600,
169	  staff: 800,
170	  potion: 400,
171	  rune: 250,
172	  moonstone: 250,
173	};
174	
175	const CAP_MULTIPLIER = 2;
176	
177	export function insuranceSum(items: Item[]): number {
178	  return items.reduce((total, item) => total + ITEM_INSURANCE_VALUES[item.type], 0);
179	}
180	
181	export function cap(items: Item[]): number {
182	  return CAP_MULTIPLIER * insuranceSum(items);
183	}
184	
185	export function quote(input: QuoteInput): number {
186	  const policyBase = calculatePolicyBase(input.items);
187	  const itemSurcharges = calculateItemSurcharges(input.items);
188	  const firstInsuranceSurcharge = calculateFirstInsuranceSurcharge(policyBase);
189	  const loyaltyDiscount = calculateLoyaltyDiscount(input.customer, policyBase);
190	  const followUpDiscount = calculateFollowUpDiscount(input.customer, policyBase);
191	  return Math.ceil(
192	    policyBase +
193	      itemSurcharges +
194	      firstInsuranceSurcharge +
195	      PROCESSING_FEE -
196	      loyaltyDiscount -
197	      followUpDiscount
198	  );
199	}
